() => {
  // Search all script tags for fbq/pixel references
  const scripts = [...document.querySelectorAll('script')];
  const found = [];
  scripts.forEach((s, i) => {
    const src = s.src || '';
    const txt = s.innerText || s.textContent || '';
    if (src.includes('facebook') || txt.includes('fbq') || txt.includes('fbevents') || txt.includes('1496775') || txt.includes('1195568')) {
      found.push({ index: i, src: src.slice(0,200), snippet: txt.slice(0,500) });
    }
  });
  return found;
}
